const locationId = 'x7nLyDSHiewYRtwYlX0h';
const tags = ['platinum', 'software subscription'];
const ghlApiKey = $env.GHL_LOCATION_API_KEY;
let allContacts = [];
for (const tag of tags) {
  let skip = 0;
  const limit = 100;
  let hasMore = true;
  while (hasMore) {
    const url = `https://services.leadconnectorhq.com/contacts/?locationId=${locationId}&limit=${limit}${skip ? '&skip=' + skip : ''}&tag=${encodeURIComponent(tag)}`;
    const response = await fetch(url, { headers: { 'Authorization': `Bearer ${ghlApiKey}`, 'Version': '2021-07-28', 'Accept': 'application/json' } });
    const data = await response.json();
    const contacts = data.contacts || [];
    for (const c of contacts) {
      if (!allContacts.find(existing => existing.id === c.id)) {
        allContacts.push({ id: c.id, firstName: c.firstName || '', lastName: c.lastName || '', email: c.email || '', phone: c.phone || '', tags: c.tags || [] });
      }
    }
    skip += limit;
    hasMore = contacts.length === limit;
  }
}
return allContacts.map(c => ({ json: c }));

const contact = $input.first().json;
const locationId = 'x7nLyDSHiewYRtwYlX0h';
const ghlApiKey = $env.GHL_LOCATION_API_KEY;
